// Store and retrieve simple values
localStorage.setItem('theme', 'dark');
const theme = localStorage.getItem('theme'); // 'dark'

// Store objects (must serialize to JSON)
const user = { name: 'Alice', preferences: { lang: 'en' } };
localStorage.setItem('user', JSON.stringify(user));

// Retrieve objects (must parse from JSON)
const stored = localStorage.getItem('user');
const parsedUser = stored ? JSON.parse(stored) : null;

// Remove a specific item
localStorage.removeItem('theme');

// Clear everything
localStorage.clear();

// Safe wrapper function (handles errors and missing values)
function getStoredValue<T>(key: string, fallback: T): T {
  try {
    const item = localStorage.getItem(key);
    return item ? (JSON.parse(item) as T) : fallback;
  } catch {
    return fallback;
  }
}

const savedTheme = getStoredValue('theme', 'light');
